document.addEventListener("DOMContentLoaded",function(){const themeToggle=document.querySelector("#theme");const rootElement=document.documentElement;let savedTheme=localStorage.getItem("theme")||"light";rootElement.setAttribute("data-theme",savedTheme);themeToggle.checked=savedTheme==="dark";themeToggle.addEventListener("change",function(){const newTheme=themeToggle.checked?"dark":"light";rootElement.setAttribute("data-theme",newTheme);localStorage.setItem("theme",newTheme)})});const canvas=document.getElementById("rain");const ctx=canvas.getContext("2d");function resizeCanvas(){const width=document.documentElement.clientWidth;const height=document.documentElement.clientHeight;canvas.width=width;canvas.height=height;canvas.style.width="100%";canvas.style.height="100%";canvas.style.position="fixed";canvas.style.top="0";canvas.style.left="0";canvas.style.pointerEvents="none";canvas.style.zIndex="0"}resizeCanvas();const raindrops=[];const ripples=[];const maxRaindrops=600;class Rain{constructor(x,y,speed,radius){this.x=x;this.y=y;this.speed=speed;this.radius=radius;this.alpha=Math.random()*.5+.5;this.windEffect=Math.random()*2.5+.5;this.twinkle=Math.random()*.05+.02}draw(){ctx.beginPath();ctx.arc(this.x,this.y,this.radius,0,Math.PI*2);ctx.fillStyle=`rgba(173, 216, 230, ${this.alpha})`;ctx.fill()}fall(){this.y+=this.speed;this.x+=this.windEffect;this.alpha+=this.twinkle*(Math.random()>.5?1:-1);this.alpha=Math.max(.1,Math.min(this.alpha,1));this.alpha-=.002;if(this.y>=canvas.height){this.createRipple();return false}this.draw();return true}createRipple(){ripples.push(new Ripple(this.x,canvas.height,2,.5))}}class Ripple{constructor(x,y,radius,growthRate){this.x=x;this.y=y;this.radius=radius;this.growthRate=growthRate*.9;this.alpha=.5}draw(){ctx.beginPath();ctx.arc(this.x,this.y,this.radius,0,Math.PI*2);ctx.strokeStyle=`rgba(255, 255, 255, ${this.alpha})`;ctx.lineWidth=1.2;ctx.stroke()}expand(){this.radius+=this.growthRate;this.alpha-=.015;this.draw();return this.alpha>0}}function createRain(){if(raindrops.length<maxRaindrops){const x=Math.random()*(canvas.width+60)-30;const speed=Math.random()*4+.5;const radius=Math.random()*3+2;raindrops.push(new Rain(x,0,speed,radius))}}function animate(){ctx.clearRect(0,0,canvas.width,canvas.height);for(let i=raindrops.length-1;i>=0;i--){if(!raindrops[i].fall()){raindrops.splice(i,1)}}for(let i=ripples.length-1;i>=0;i--){if(!ripples[i].expand()){ripples.splice(i,1)}}requestAnimationFrame(animate)}setInterval(createRain,15);animate();window.addEventListener("resize",()=>{resizeCanvas()});const SVG_NS="http://www.w3.org/2000/svg";const MAX_FLOWER_AGE=50;const MAX_GROWTH_TICKS=18;const BRANCH_COLOR="rgb(80, 50, 30)";const MAX_ACTIVE_FLOWERS=100;function shadeRGBColor(color,percent){const[r,g,b]=color.match(/\d+/g).map(Number);const t=percent<0?0:255;const p=Math.abs(percent);const R=Math.round((t-r)*p+r);const G=Math.round((t-g)*p+g);const B=Math.round((t-b)*p+b);return`rgb(${R},${G},${B})`}(()=>{const maxDepth=11;const branchShrinkage=.82;const maxAngleDelta=Math.PI/4;const branchDelay=100;const svg=document.getElementById("svg");const scaleIncrement=.12;const flowerSize=10;const dropIncrement=2.5;const rotateIncrement=Math.PI*2;let wind=0;const windIncrement=1;const maxWind=2;let viewportWidth=window.innerWidth;let viewportHeight=window.innerHeight;svg.setAttribute("width",viewportWidth);svg.setAttribute("height",viewportHeight);window.addEventListener("resize",()=>{viewportWidth=window.innerWidth;viewportHeight=window.innerHeight;svg.setAttribute("width",viewportWidth);svg.setAttribute("height",viewportHeight)});class Flower{constructor(x,y,idx){this.x=x;this.y=y;this.idx=idx;this.telemeres=MAX_FLOWER_AGE;this.growthPhase=0;this.attached=true;this.hangPhase=1;this.scale=.5;this.rotation=0;this.element=document.createElementNS(SVG_NS,"use");this.element.setAttribute("href","#flower");this.element.style.zIndex="-1";this.transform();const children=svg.childNodes;const randomIndex=children.length?Math.floor(Math.random()*children.length):null;if(randomIndex!==null){svg.insertBefore(this.element,children[randomIndex])}else{svg.appendChild(this.element)}}grow(){this.growthPhase++;this.scale+=scaleIncrement*Math.random()}drop(){this.y+=dropIncrement*Math.random();this.x+=dropIncrement*Math.random()+wind;this.rotation+=rotateIncrement*(Math.random()-.5)}transform(){const radius=this.scale*flowerSize/1.8;this.element.setAttribute("transform",`translate(${this.x-radius}, ${this.y-radius}) scale(${this.scale}) rotate(${this.rotation})`)}step(){if(this.y>=viewportHeight+flowerSize){this.telemeres=0}else if(this.growthPhase>=MAX_GROWTH_TICKS){if(this.attached){this.attached=Math.random()<Math.pow(.9999,this.hangPhase);this.hangPhase+=2e-4}else{this.drop()}}else{this.grow()}this.transform();return this.telemeres}delete(){svg.removeChild(this.element)}}const createFlower=({x:x,y:y,idx:idx})=>new Flower(x,y,idx);const animateFlowers=branchEndings=>{const branchesInUse=new Set;const flowers=[];const findFreeBranchIdx=()=>{const available=[];for(let i=0;i<branchEndings.length;i++){if(!branchesInUse.has(i))available.push(i)}if(!available.length)return-1;const idx=available[Math.floor(Math.random()*available.length)];branchesInUse.add(idx);return idx};const attachFlower=()=>{if(flowers.length>=MAX_ACTIVE_FLOWERS)return;const idx=findFreeBranchIdx();if(idx>=0){const branch=branchEndings[idx];flowers.push(createFlower({...branch,idx:idx}))}};const tick=()=>{for(let i=flowers.length-1;i>=0;i--){if(flowers[i].step()<=0){branchesInUse.delete(flowers[i].idx);flowers[i].delete();flowers.splice(i,1)}}for(let i=0;i<5;i++){if(Math.random()<.02)attachFlower()}if(Math.random()<.02){wind=Math.max(-maxWind,Math.min(maxWind,wind+(Math.random()*2-1)*windIncrement))}requestAnimationFrame(tick)};requestAnimationFrame(tick)};async function drawBranch(x1,y1,length,angle,depth,branchWidth,branchColor){const x2=x1+length*Math.cos(angle);const y2=y1+length*Math.sin(angle);const line=document.createElementNS(SVG_NS,"line");line.setAttribute("x1",x1);line.setAttribute("y1",y1);line.setAttribute("x2",x2);line.setAttribute("y2",y2);line.setAttribute("style",`stroke: ${branchColor}; stroke-width: ${branchWidth};`);svg.appendChild(line);if(depth<=0)return[{x:x2,y:y2}];await new Promise(resolve=>setTimeout(resolve,branchDelay));if(y2>viewportHeight&&y2-viewportHeight>=35||y2>=viewportHeight-100){return[{x:x2,y:y2}]}const branches=await Promise.all([-1,1].map(async direction=>drawBranch(x2,y2,length*branchShrinkage,angle+Math.PI/4*direction*Math.random(),depth-.9,branchWidth*branchShrinkage,shadeRGBColor(branchColor,.06))));return branches.flat()}const init=async()=>{const branchEndings=await drawBranch(viewportWidth*.35,viewportHeight,125,-Math.PI/2,maxDepth,21,BRANCH_COLOR);animateFlowers(branchEndings)};init()})();